#include <stdio.h>
#include <stdbool.h>

#define TABLE_SIZE 11

typedef struct {
    int key;
    bool occupied;
    bool deleted;  // For lazy deletion
} HashEntry;

HashEntry hashTable[TABLE_SIZE];

int hash1(int key) {
    return key % TABLE_SIZE;
}

int hash2(int key) {
    return 7 - (key % 7);  // Prime smaller than TABLE_SIZE
}

int doubleHash(int key, int i) {
    return (hash1(key) + i * hash2(key)) % TABLE_SIZE;
}

void insert(int key) {
    int i = 0;
    int index;

    while (i < TABLE_SIZE) {
        index = doubleHash(key, i);
        if (!hashTable[index].occupied) {
            hashTable[index].key = key;
            hashTable[index].occupied = true;
            hashTable[index].deleted = false;
            printf("Inserted %d at index %d\n", key, index);
            return;
        }
        i++;
    }
    printf("Table full, cannot insert %d\n", key);
}

int search(int key) {
    int i = 0;
    int index;

    while (i < TABLE_SIZE) {
        index = doubleHash(key, i);
        if (!hashTable[index].occupied) {
            return -1;  // Not found
        }
        if (hashTable[index].key == key && !hashTable[index].deleted) {
            return index;
        }
        i++;
    }
    return -1;
}

int main() {
    int keys[] = {15, 22, 31, 4, 17};
    int n = sizeof(keys) / sizeof(keys[0]);

    for (int i = 0; i < n; i++) {
        insert(keys[i]);
    }

    int result = search(22);
    if (result != -1)
        printf("Found at index %d\n", result);

    return 0;
}

import java.util.*;

public class RehashHashMap {
    private static final double LOAD_FACTOR_THRESHOLD = 0.75;
    private Map<Integer, String> hashMap;
    private int capacity;
    private int size;

    public RehashHashMap(int initialCapacity) {
        this.capacity = initialCapacity;
        this.hashMap = new HashMap<>(capacity);
    }

    private void rehash() {
        System.out.println("Rehashing triggered...");
        Map<Integer, String> oldMap = hashMap;

        // Double the capacity
        capacity = capacity * 2;
        hashMap = new HashMap<>(capacity);
        size = 0;

        // Re-insert all elements
        for (Integer key : oldMap.keySet()) {
            hashMap.put(key, oldMap.get(key));
        }
        System.out.println("Rehashing complete. New capacity: " + capacity);
    }

    public void put(Integer key, String value) {
        double loadFactor = (double) size / capacity;
        System.out.println("Load factor: " + String.format("%.2f", loadFactor));

        if (loadFactor >= LOAD_FACTOR_THRESHOLD) {
            rehash();
        }
        hashMap.put(key, value);
        size++;
    }

    public static void main(String[] args) {
        RehashHashMap map = new RehashHashMap(4);

        map.put(1, "One");
        map.put(2, "Two");
        map.put(3, "Three");
        map.put(4, "Four");  // Triggers rehash
        map.put(5, "Five");
    }
}
